using sv_db19db13b1274267b7ccf0b5763240f7.Client.Services;

namespace sv_db19db13b1274267b7ccf0b5763240f7.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Seeds = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 23, 8, 15, 0, TimeSpan.Zero), Description = "In transit to Chicago, IL" },
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "Austin, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 22, 12, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 16, 0, 0, TimeSpan.Zero), Description = "Arrived at regional hub" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 7, 45, 0, TimeSpan.Zero), Description = "Out for delivery" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 11, 20, 0, TimeSpan.Zero), Description = "Delivered" },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 24, 8, 0, 0, TimeSpan.Zero), Description = "Order received" },
            ]
        },
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (Seeds.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment '{trackingNumber}' not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@implements IAsyncDisposable
@inject IShipmentService ShipmentSvc
@inject ILogger<ShipmentTracker> Logger
@using sv_db19db13b1274267b7ccf0b5763240f7.Client.Services

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (isLoading)
{
    <p>Loading shipment <strong>@TrackingNumber</strong>…</p>
}
else if (errorMessage is not null)
{
    <div class="error">
        <p>@errorMessage</p>
        <button @onclick="Retry">Retry</button>
    </div>
}
else if (shipment is not null)
{
    <h2>Shipment @shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@shipment.Status</dd>
        <dt>Location</dt>
        <dd>@shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    <ul>
        @foreach (var update in shipment.Updates)
        {
            <li @key="update.Timestamp">
                <strong>@update.Timestamp.ToString("g")</strong> — @update.Description
            </li>
        }
    </ul>
}

@code {
    [Parameter] public string TrackingNumber { get; set; } = "";

    private string currentTrackingNumber = "";
    private Shipment? shipment;
    private bool isLoading;
    private string? errorMessage;
    private CancellationTokenSource cts = new();

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(currentTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase))
        {
            return;
        }

        currentTrackingNumber = TrackingNumber;
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        await cts.CancelAsync();
        cts.Dispose();
        cts = new CancellationTokenSource();

        shipment = null;
        errorMessage = null;
        isLoading = true;

        try
        {
            shipment = await ShipmentSvc.GetShipmentAsync(currentTrackingNumber, cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Navigation changed or component disposed — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", currentTrackingNumber);
            errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", currentTrackingNumber);
            errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task Retry()
    {
        await LoadShipmentAsync();
    }

    public ValueTask DisposeAsync()
    {
        cts.Cancel();
        cts.Dispose();
        return ValueTask.CompletedTask;
    }
}

